// application.properties:
// spring.batch.job.enabled=false (disable auto-start)
// spring.datasource.url=jdbc:h2:mem:testdb

// ── Model ────────────────────────────────────────────────────
public record Employee(Long id, String name, double salary) {}

// ── Configuration ────────────────────────────────────────────
@Configuration
@EnableBatchProcessing
public class BatchConfig {

    // 1. Reader: reads employees.csv line by line
    @Bean
    public FlatFileItemReader<Employee> csvReader() {
        return new FlatFileItemReaderBuilder<Employee>()
            .name("employeeReader")
            .resource(new ClassPathResource("employees.csv"))
            .delimited()
            .names("id", "name", "salary")
            .targetType(Employee.class)
            .build();
    }

    // 2. Processor: give 10% raise to employees earning < 50000
    @Bean
    public ItemProcessor<Employee, Employee> raiseProcessor() {
        return emp -> emp.salary() < 50_000
            ? new Employee(emp.id(), emp.name(), emp.salary() * 1.10)
            : emp; // return null to skip an item
    }

    // 3. Writer: bulk INSERT into employees table
    @Bean
    public JdbcBatchItemWriter<Employee> dbWriter(DataSource ds) {
        return new JdbcBatchItemWriterBuilder<Employee>()
            .sql("INSERT INTO employees (id, name, salary) VALUES (:id, :name, :salary)")
            .dataSource(ds)
            .beanMapped()   // maps Employee fields to :placeholders
            .build();
    }

    // 4. Step: tie reader → processor → writer with chunk size 100
    @Bean
    public Step processEmployeesStep(JobRepository repo, PlatformTransactionManager tm,
            FlatFileItemReader<Employee> reader,
            ItemProcessor<Employee, Employee> processor,
            JdbcBatchItemWriter<Employee> writer) {
        return new StepBuilder("processEmployees", repo)
            .<Employee, Employee>chunk(100, tm)   // 100 items per transaction
            .reader(reader)
            .processor(processor)
            .writer(writer)
            .faultTolerant()
            .skip(FlatFileParseException.class)   // skip malformed CSV lines
            .skipLimit(10)                        // but only up to 10 skips
            .build();
    }

    // 5. Job: one step (can chain multiple)
    @Bean
    public Job importEmployeesJob(JobRepository repo, Step processEmployeesStep) {
        return new JobBuilder("importEmployees", repo)
            .start(processEmployeesStep)
            .build();
    }
}

// ── Trigger via REST ──────────────────────────────────────────
@RestController
@RequestMapping("/batch")
public class BatchController {
    @Autowired JobLauncher launcher;
    @Autowired Job importEmployeesJob;

    @PostMapping("/run")
    public String run() throws Exception {
        JobParameters params = new JobParametersBuilder()
            .addLong("run.id", System.currentTimeMillis())  // unique params = new run
            .toJobParameters();
        JobExecution exec = launcher.run(importEmployeesJob, params);
        return exec.getStatus().toString(); // COMPLETED or FAILED
    }
}

