import java.util.*;

public class Q2 {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int total = 0, skipped = 0;
        while (sc.hasNextInt()) {
            int n = sc.nextInt();
            if (n % 7 == 0) { skipped++; }
            else { total += n; }
        }
        System.out.println("Total: " + total);
        System.out.println("Skipped: " + skipped);
    }
}

